import { z } from 'zod';

/**
 * Zod schema for CategoryConfiguration validation
 * Validates structure per ${repoRoot}/docs/SCORING_LOGIC.md "Tuning Parameters Summary" section
 */

// Base validation schemas for reusability
const EmailAddressSchema = z.string().email();
const DomainSchema = z.string().regex(/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/, 'Invalid domain format');
const ConfidenceSchema = z.string().regex(/^(high|medium|low)$/, 'Must be high, medium, or low');
const WeightSchema = z.number().min(0).max(1);
const ThresholdSchema = z.number().min(0).max(1);

// Rule pattern validation
const RulePatternSchema = z.object({
  field: z.enum(['subject', 'body', 'from.address', 'from.name', 'to', 'headers']),
  operation: z.enum(['contains_any', 'starts_with', 'ends_with', 'regex_any', 'exists', 'not_contains']),
  values: z.array(z.string()).optional(),
  weight: WeightSchema,
});

// Attribute schemas
const AttributeRoleSchema = z.enum([
  'CORE',
  'PRIMARY_BOOST',
  'SECONDARY_BOOST',
  'DISAMBIGUATOR',
  'FILTER',
  'STRUCTURAL',
  'DERIVED_LINK',
  'NEUTRAL',
]);

const AttributeSchemaDefinition = z.object({
  type: z.enum(['enum', 'boolean', 'string', 'number']),
  values: z.array(z.string()).optional(),
  description: z.string(),
  validation: z
    .object({
      required: z.boolean().default(false),
      min: z.number().optional(),
      max: z.number().optional(),
      pattern: z.string().optional(),
    })
    .optional(),
});

const AttributeDetectorSchema = z.object({
  attribute: z.string(),
  field: z.string(),
  operation: z.string(),
  values: z.array(z.string()),
  confidence: z.number().min(0).max(1).default(1.0),
  parallel_safe: z.boolean().default(true),
});

const DerivedAttributeSchema = z.object({
  logic: z.string(),
  notes: z.string(),
  dependencies: z.array(z.string()).default([]),
  parallel_safe: z.boolean().default(false),
});

// Domain reference schemas
const DomainReferenceSchema = z.object({
  source_group: z.string(),
  confidence: ConfidenceSchema,
  weight_multiplier: z.number().min(0).max(2).default(1.0),
});

// Category signal schemas
const HardAssertionsSchema = z.object({
  from_domains_ref: DomainReferenceSchema.optional(),
  subject_prefixes: z.array(z.string()).optional(),
  from_addresses: z.array(EmailAddressSchema).optional(),
  custom_rules: z.array(RulePatternSchema).optional(),
});

const StrongIndicatorsSchema = z.object({
  from_domains_ref: DomainReferenceSchema.optional(),
  subject_contains: z.array(z.string()).optional(),
  body_contains: z.array(z.string()).optional(),
  custom_rules: z.array(RulePatternSchema).optional(),
  diminishing_returns: z
    .object({
      enabled: z.boolean().default(true),
      decay_factor: z.number().min(0).max(1).default(0.8),
      max_indicators: z.number().int().min(1).default(5),
    })
    .optional(),
});

const DisambiguatorsSchema = z.object({
  boost_if_present_attributes: z.array(z.string()).optional(),
  suppress_if_body_contains: z.array(z.string()).optional(),
  boost_if_absent_categories: z.array(z.string()).optional(),
  pairwise_adjustments: z
    .array(
      z.object({
        target_category: z.string(),
        condition: z.string(),
        adjustment: z.number().min(-1).max(1),
        reason: z.string(),
      })
    )
    .optional(),
});

const CategorySignalsSchema = z.object({
  hard_assertions: HardAssertionsSchema.optional(),
  strong_indicators: StrongIndicatorsSchema.optional(),
  disambiguators: DisambiguatorsSchema.optional(),
  validation: z
    .object({
      required_fields: z.array(z.string()).default([]),
      mutually_exclusive: z.array(z.array(z.string())).default([]),
    })
    .optional(),
});

// Subtype definition schema
const SubtypeDefinitionSchema = z.object({
  description: z.string(),
  rule_based_classification: z
    .object({
      high_confidence: z.array(RulePatternSchema).optional(),
      medium_confidence: z.array(RulePatternSchema).optional(),
      low_confidence: z.array(RulePatternSchema).optional(),
    })
    .optional(),
  derived: z.boolean().default(false),
  derivation_logic: z.string().optional(),
  parallel_safe: z.boolean().default(true),
  tuning_parameters: z
    .object({
      K_high: z.number().min(0).default(1.0),
      K_medium: z.number().min(0).default(0.7),
      K_low: z.number().min(0).default(0.3),
      max_rule_score: z.number().min(0).default(1.0),
    })
    .optional(),
});

// Top level category schema
const TopLevelCategorySchema = z.object({
  description: z.string(),
  subtypes: z.record(z.string(), SubtypeDefinitionSchema),
  ai_final_classification: z.object({
    category_description: z.string(),
    decision_criteria: z.array(z.string()),
    exclusion_criteria: z.array(z.string()).optional(),
    prompt_template: z.string().optional(),
  }),
  tuning_parameters: z
    .object({
      confidence_boost: z.number().min(0).max(1).default(0),
      priority_weight: z.number().min(0).max(2).default(1.0),
      max_score_cap: z.number().min(0).default(1.0),
    })
    .optional(),
});

// Processing settings schema
const ProcessingSettingsSchema = z.object({
  initialization: z.object({
    apply_hard_assertions: z.boolean().default(true),
    seed_category_scores: z.boolean().default(true),
    parallel_initialization: z.boolean().default(true),
  }),
  rule_scoring: z.object({
    use_lexical_patterns: z.boolean().default(true),
    apply_subtype_rules: z.boolean().default(true),
    bounded_aggregation: z.boolean().default(true),
    parallel_rule_evaluation: z.boolean().default(true),
    tuning_parameters: z.object({
      K_high: z.number().min(0).default(1.0),
      K_medium: z.number().min(0).default(0.7),
      K_low: z.number().min(0).default(0.3),
      aggregation_cap: z.number().min(0).default(1.0),
    }),
  }),
  attribute_processing: z.object({
    detect_self_sent: z.boolean().default(true),
    resolve_domains: z.boolean().default(true),
    derive_context_flags: z.boolean().default(true),
    parallel_detection: z.boolean().default(true),
    cache_attribute_results: z.boolean().default(true),
  }),
  attribute_influence: z.object({
    apply_bonuses: z.boolean().default(true),
    apply_penalties: z.boolean().default(true),
    enforce_caps: z.boolean().default(true),
    parallel_influence_calculation: z.boolean().default(true),
    tuning_parameters: z.object({
      bonus_multiplier: z.number().min(0).default(1.0),
      penalty_multiplier: z.number().min(0).default(1.0),
      max_total_bonus: z.number().min(0).default(0.5),
      max_total_penalty: z.number().min(0).default(0.3),
    }),
  }),
  disambiguation: z.object({
    pairwise_adjustments: z.boolean().default(true),
    confidence_gap_threshold: ThresholdSchema.default(0.1),
    max_adjustments_per_category: z.number().int().min(1).default(3),
  }),
  multi_label_selection: z.object({
    max_labels: z.number().int().min(1).default(3),
    min_secondary_confidence: ThresholdSchema.default(0.6),
    allowed_combinations: z.array(z.string()).default([]),
    confidence_gap_minimum: z.number().min(0).default(0.15),
  }),
  ai_routing: z.object({
    high_confidence_threshold: ThresholdSchema.default(0.8),
    ai_required_threshold: ThresholdSchema.default(0.4),
    skip_ai_conditions: z.array(z.string()).default([]),
    batch_size: z.number().int().min(1).default(10),
    timeout_ms: z.number().int().min(1000).default(30000),
  }),
  performance: z.object({
    parallel_processing: z.boolean().default(true),
    max_parallel_emails: z.number().int().min(1).default(10),
    batch_size: z.number().int().min(1).default(50),
    enable_caching: z.boolean().default(true),
    cache_ttl_seconds: z.number().int().min(60).default(3600),
  }),
});

// Confidence thresholds schema
const ConfidenceThresholdsSchema = z.object({
  high_confidence: ThresholdSchema.default(0.8),
  medium_confidence: ThresholdSchema.default(0.6),
  low_confidence: ThresholdSchema.default(0.4),
  ai_classification_required: ThresholdSchema.default(0.4),
  manual_review_required: ThresholdSchema.default(0.2),
  secondary_label_min_gap: z.number().min(0).default(0.15),
  tuning_parameters: z
    .object({
      confidence_decay_factor: z.number().min(0).max(1).default(0.95),
      uncertainty_penalty: z.number().min(0).max(0.5).default(0.1),
    })
    .optional(),
});

// Multi-label policy schema
const MultiLabelPolicySchema = z.object({
  max_top_level_labels: z.number().int().min(1).default(3),
  min_confidence_for_additional: ThresholdSchema.default(0.6),
  min_delta_primary_secondary: z.number().min(0).default(0.15),
  allow_financial_actionable_copresence: z.boolean().default(false),
  allowed_combinations: z
    .array(
      z.object({
        categories: z.array(z.string()),
        max_confidence_sum: z.number().min(0).default(2.0),
        notes: z.string().optional(),
      })
    )
    .default([]),
  exclusions: z
    .array(
      z.object({
        categories: z.array(z.string()),
        reason: z.string(),
      })
    )
    .default([]),
});

// Domain overrides schema
const DomainOverridesSchema = z.record(
  z.string(),
  z.object({
    hard_include: z.array(DomainSchema).default([]),
    hard_exclude: z.array(DomainSchema).default([]),
    strong_include: z.array(DomainSchema).default([]),
    strong_exclude: z.array(DomainSchema).default([]),
    notes: z.string().optional(),
  })
);

// Domain resolution schema
const DomainResolutionSchema = z.object({
  mode: z.enum(['runtime_resolved', 'static', 'hybrid']).default('runtime_resolved'),
  source: z.string().default('config/domain-sources.json'),
  notes: z.string().optional(),
  cache_settings: z
    .object({
      enable_caching: z.boolean().default(true),
      cache_ttl_seconds: z.number().int().min(60).default(3600),
      max_cache_entries: z.number().int().min(100).default(10000),
    })
    .optional(),
});

// Attribute system schema
const AttributeSystemSchema = z.object({
  schema: z.record(z.string(), AttributeSchemaDefinition),
  detectors: z.array(AttributeDetectorSchema),
  derived: z.record(z.string(), DerivedAttributeSchema),
  attribute_bonus_map: z.record(z.string(), z.record(z.string(), z.number())),
  parallel_processing: z
    .object({
      enable_parallel_detection: z.boolean().default(true),
      max_parallel_detectors: z.number().int().min(1).default(5),
      batch_derived_attributes: z.boolean().default(true),
    })
    .optional(),
});

// Attribute relevance matrix schema
const AttributeRelevanceMatrixSchema = z
  .object({
    _roles_legend: z.object({
      CORE: z.string(),
      PRIMARY_BOOST: z.string(),
      SECONDARY_BOOST: z.string(),
      DISAMBIGUATOR: z.string(),
      FILTER: z.string(),
      STRUCTURAL: z.string(),
      DERIVED_LINK: z.string(),
      NEUTRAL: z.string(),
    }),
  })
  .and(
    z.record(
      z.string(),
      z.object({
        category_roles: z.record(z.string(), AttributeRoleSchema),
        subtypes: z
          .record(
            z.string(),
            z.object({
              roles: z.record(z.string(), AttributeRoleSchema),
            })
          )
          .optional(),
        tuning_parameters: z
          .object({
            bonus_multipliers: z.record(z.string(), z.number().min(0).default(1.0)),
            penalty_multipliers: z.record(z.string(), z.number().min(0).default(1.0)),
            max_influence: z.number().min(0).default(0.5),
          })
          .optional(),
      })
    )
  );

// AI prompt system schema
const AIPromptSystemSchema = z.object({
  feature_extraction: z.object({
    system_prompt: z.array(z.string()),
    user_prompt: z.array(z.string()),
    temperature: z.number().min(0).max(2).default(0.1),
    max_tokens: z.number().int().min(100).default(1000),
  }),
  final_classification: z.object({
    system_prompt: z.array(z.string()),
    user_prompt: z.array(z.string()),
    temperature: z.number().min(0).max(2).default(0.1),
    max_tokens: z.number().int().min(50).default(500),
  }),
  model_settings: z
    .object({
      model_name: z.string().default('gpt-4'),
      fallback_model: z.string().default('gpt-3.5-turbo'),
      request_timeout_ms: z.number().int().min(1000).default(30000),
      retry_attempts: z.number().int().min(0).default(3),
    })
    .optional(),
});

// JSON Schema validation (for feature extraction schema)
const JSONSchemaSchema = z.object({
  type: z.string(),
  properties: z.record(z.string(), z.any()),
  required: z.array(z.string()),
  additionalProperties: z.boolean().default(false),
  $schema: z.string().optional(),
  title: z.string().optional(),
  description: z.string().optional(),
});

// Main processing config schema
const ProcessingConfigSchema = z.object({
  version: z.number().int().min(1),
  taxonomy_notes: z.string(),
  settings: ProcessingSettingsSchema,
  category_signals: z.record(z.string(), CategorySignalsSchema),
  confidence_thresholds: ConfidenceThresholdsSchema,
  multi_label_policy: MultiLabelPolicySchema,
  domain_signal_overrides: DomainOverridesSchema,
  domain_signal_resolution: DomainResolutionSchema,
  top_level_categories: z.record(z.string(), TopLevelCategorySchema),
  attributes: AttributeSystemSchema,
  attribute_relevance: AttributeRelevanceMatrixSchema,
  ai_prompts: AIPromptSystemSchema,
  feature_extraction_schema: JSONSchemaSchema,
});

// Main category configuration schema
export const CategoryConfigurationSchema = z.object({
  version: z.string().regex(/^\d+\.\d+\.\d+$/, 'Must be semantic version format (x.y.z)'),
  lastModified: z.coerce.date(),
  hash: z.string().length(64, 'Must be SHA-256 hash'),

  // Main processing configuration
  processing_config: ProcessingConfigSchema,

  // Validation metadata
  schemaVersion: z.string().default('1.0.0'),
  validationPassed: z.boolean(),
  validationErrors: z.array(z.string()).default([]),

  // Runtime optimization (these will be populated by the system)
  compiledRules: z
    .array(
      z.object({
        category: z.string(),
        subtype: z.string(),
        tier: z.enum(['high', 'medium', 'low']),
        pattern: z.any(), // RegExp objects can't be validated by Zod
        weight: z.number(),
        parallel_safe: z.boolean().default(true),
      })
    )
    .optional(),

  attributeMatrix: z
    .record(
      z.string(),
      z.record(
        z.string(),
        z.object({
          role: AttributeRoleSchema,
          bonus: z.number(),
          cap: z.number(),
        })
      )
    )
    .optional(),

  // Performance metadata
  performanceMetrics: z
    .object({
      last_validation_time_ms: z.number().optional(),
      rule_compilation_time_ms: z.number().optional(),
      matrix_computation_time_ms: z.number().optional(),
      total_categories: z.number().int().optional(),
      total_rules: z.number().int().optional(),
      parallel_compatible_rules: z.number().int().optional(),
    })
    .optional(),
});

// Type inference
export type CategoryConfiguration = z.infer<typeof CategoryConfigurationSchema>;
export type ProcessingConfig = z.infer<typeof ProcessingConfigSchema>;
export type ProcessingSettings = z.infer<typeof ProcessingSettingsSchema>;
export type CategorySignals = z.infer<typeof CategorySignalsSchema>;
export type AttributeRole = z.infer<typeof AttributeRoleSchema>;
export type RulePattern = z.infer<typeof RulePatternSchema>;
export type TopLevelCategory = z.infer<typeof TopLevelCategorySchema>;
export type SubtypeDefinition = z.infer<typeof SubtypeDefinitionSchema>;
export type AttributeSystem = z.infer<typeof AttributeSystemSchema>;
export type AttributeRelevanceMatrix = z.infer<typeof AttributeRelevanceMatrixSchema>;
export type AIPromptSystem = z.infer<typeof AIPromptSystemSchema>;

// Validation helper functions
export const validateCategoryConfiguration = (config: unknown): CategoryConfiguration => {
  return CategoryConfigurationSchema.parse(config);
};

export const validateProcessingConfig = (config: unknown): ProcessingConfig => {
  return ProcessingConfigSchema.parse(config);
};

// Partial validation for specific sections
export const validateCategorySignals = (signals: unknown): CategorySignals => {
  return CategorySignalsSchema.parse(signals);
};

export const validateAttributeSystem = (system: unknown): AttributeSystem => {
  return AttributeSystemSchema.parse(system);
};

export const validateProcessingSettings = (settings: unknown): ProcessingSettings => {
  return ProcessingSettingsSchema.parse(settings);
};

// Schema validation utilities
export const getSchemaVersion = () => '1.0.0';

export const isValidConfig = (config: unknown): boolean => {
  try {
    CategoryConfigurationSchema.parse(config);
    return true;
  } catch {
    return false;
  }
};

export const getValidationErrors = (config: unknown): string[] => {
  try {
    CategoryConfigurationSchema.parse(config);
    return [];
  } catch (error) {
    if (error instanceof z.ZodError) {
      return error.errors.map((err) => `${err.path.join('.')}: ${err.message}`);
    }
    return ['Unknown validation error'];
  }
};

